   463→/// Helper to convert PaceState to display string
   464→pub(crate) fn zjjrpd_pace_state_str(state: &PaceState) -> &'static str {
   465→    match state {
   466→        PaceState::Rough => "rough",
   467→        PaceState::Bridled => "bridled",
   468→        PaceState::Complete => "complete",
   469→        PaceState::Abandoned => "abandoned",
   470→    }
   471→}
