   473→/// Resolve the default heat (first racing heat) when no target is specified
   474→pub(crate) fn zjjrpd_resolve_default_heat(gallops: &Gallops) -> Result<String, String> {
   475→    for (heat_key, heat) in &gallops.heats {
   476→        if heat.status == HeatStatus::Racing {
   477→            return Ok(heat_key.clone());
   478→        }
   479→    }
   480→    Err("No racing heats found".to_string())
